from sqlalchemy import select, insert, text, func, Index
from sqlalchemy.ext.asyncio import AsyncSession
from sqlalchemy.orm import (
    DeclarativeBase,
    Mapped,
    mapped_column,
    selectinload,
)
from fastapi import FastAPI, Depends
from typing import Annotated
from datetime import datetime


class Base(DeclarativeBase):
    pass

class Product(Base):
    __tablename__ = "products"
    id: Mapped[int] = mapped_column(primary_key=True)
    name: Mapped[str] = mapped_column(index=True)
    category: Mapped[str] = mapped_column(index=True)
    price: Mapped[float]
    created_at: Mapped[datetime] = mapped_column(default=datetime.utcnow)

    # Composite index for common query patterns
    __table_args__ = (
        Index("ix_category_price", "category", "price"),
    )


app = FastAPI()


# --- 1. Select only needed columns ---
@app.get("/products/list")
async def list_products(db: Annotated[AsyncSession, Depends(get_db)]):
    # GOOD: Fetch only id and name
    result = await db.execute(
        select(Product.id, Product.name)
    )
    return [{"id": r.id, "name": r.name} for r in result]

    # BAD: Fetches ALL columns including large text fields
    # result = await db.execute(select(Product))


# --- 2. Efficient filtering with indexes ---
@app.get("/products/search")
async def search_products(
    db: Annotated[AsyncSession, Depends(get_db)],
    category: str = "electronics",
    max_price: float = 100.0,
):
    # Uses composite index (category, price)
    result = await db.execute(
        select(Product)
        .where(Product.category == category)
        .where(Product.price <= max_price)
        .order_by(Product.price)
        .limit(50)
    )
    return result.scalars().all()


# --- 3. Bulk insert (much faster than individual inserts) ---
@app.post("/products/bulk")
async def bulk_create(
    db: Annotated[AsyncSession, Depends(get_db)],
):
    products = [
        {"name": f"Product {i}", "category": "bulk", "price": i * 1.5}
        for i in range(1000)
    ]
    # Single statement instead of 1000 individual inserts
    await db.execute(insert(Product), products)
    await db.commit()
    return {"inserted": len(products)}


# --- 4. Aggregation at database level ---
@app.get("/products/stats")
async def product_stats(
    db: Annotated[AsyncSession, Depends(get_db)],
):
    # Do aggregation in the database, not Python
    result = await db.execute(
        select(
            Product.category,
            func.count(Product.id).label("count"),
            func.avg(Product.price).label("avg_price"),
            func.min(Product.price).label("min_price"),
            func.max(Product.price).label("max_price"),
        ).group_by(Product.category)
    )
    return [
        {
            "category": r.category,
            "count": r.count,
            "avg_price": round(float(r.avg_price), 2),
        }
        for r in result
    ]


# --- 5. Exists check (faster than count) ---
@app.get("/products/{product_id}/exists")
async def product_exists(
    product_id: int,
    db: Annotated[AsyncSession, Depends(get_db)],
):
    # GOOD: EXISTS stops at first match
    result = await db.execute(
        select(
            select(Product).where(Product.id == product_id).exists()
        )
    )
    return {"exists": result.scalar()}

    # BAD: COUNT scans all matching rows
